<?php
declare(strict_types=1);
function lm_row(int $id):array{$s=db()->prepare('SELECT * FROM lead_magnets WHERE id=?');$s->execute([$id]);$r=$s->fetch();if(!$r){http_response_code(404);exit('Lead magnet not found');}return $r;}
function lm_clean(string $html):string{return trim(strip_tags($html,'<h1><h2><h3><p><br><ul><ol><li><strong><em><blockquote><table><thead><tbody><tr><th><td><hr>'));}
function lm_page(array $r):string{return '<!doctype html><html><head><meta charset="utf-8"><style>@page{margin:45px}body{font:12pt/1.55 DejaVu Sans,sans-serif;color:#263238}h1,h2,h3{color:#1565c0}table{width:100%;border-collapse:collapse}td,th{border:1px solid #bbb;padding:7px}</style></head><body><h1>'.e($r['title']).'</h1>'.lm_clean((string)$r['content_html']).'</body></html>';}
function lm_ai(string $prompt):string{$key=decrypt_secret(app_setting('openai_api_key_enc'));if($key==='')throw new RuntimeException('Configure the OpenAI API key in Admin settings.');$payload=json_encode(['model'=>app_setting('openai_model','gpt-5.4-mini'),'instructions'=>'Create polished lead-magnet content. Return safe semantic HTML only. No markdown fences, scripts, styles, images, forms, or remote resources.','input'=>$prompt]);$ch=curl_init('https://api.openai.com/v1/responses');curl_setopt_array($ch,[CURLOPT_POST=>true,CURLOPT_RETURNTRANSFER=>true,CURLOPT_TIMEOUT=>180,CURLOPT_HTTPHEADER=>['Authorization: Bearer '.$key,'Content-Type: application/json'],CURLOPT_POSTFIELDS=>$payload]);$raw=curl_exec($ch);$status=(int)curl_getinfo($ch,CURLINFO_RESPONSE_CODE);$err=curl_error($ch);curl_close($ch);$data=json_decode((string)$raw,true);if($status<200||$status>=300)throw new RuntimeException('OpenAI request failed: '.mb_strimwidth((string)($data['error']['message']??$err),0,260,'…'));$text='';foreach($data['output']??[] as $o)foreach($o['content']??[] as $c)if(($c['type']??'')==='output_text')$text.=$c['text']??'';if(trim($text)==='')throw new RuntimeException('OpenAI returned no content.');return lm_clean($text);}
function lm_context():string{$out='';foreach(db()->query("SELECT title,COALESCE(NULLIF(extracted_text,''),body) body FROM knowledge_base_items ORDER BY updated_at DESC")->fetchAll() as $r)$out.="\n## {$r['title']}\n{$r['body']}";return mb_substr($out,0,140000);}
function lm_pdf(array $r):never{if(!class_exists('Dompdf\\Dompdf'))throw new RuntimeException('Dompdf is not installed.');$opt=new Dompdf\Options();$opt->set('isRemoteEnabled',false);$opt->set('isPhpEnabled',false);$pdf=new Dompdf\Dompdf($opt);$pdf->loadHtml(lm_page($r),'UTF-8');$pdf->setPaper('letter');$pdf->render();header('Content-Type: application/pdf');header('Content-Disposition: attachment; filename="lead-magnet.pdf"');echo $pdf->output();exit;}
function lm_docx(array $r):never{$tmp=tempnam(sys_get_temp_dir(),'lm');$z=new ZipArchive();$z->open($tmp,ZipArchive::OVERWRITE);$z->addFromString('[Content_Types].xml','<?xml version="1.0"?><Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types"><Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/><Default Extension="xml" ContentType="application/xml"/><Override PartName="/word/document.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.document.main+xml"/></Types>');$z->addFromString('_rels/.rels','<?xml version="1.0"?><Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"><Relationship Id="r1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="word/document.xml"/></Relationships>');$text=html_entity_decode(strip_tags(str_replace(['</p>','</h1>','</h2>','</li>'],"\n",lm_page($r))),ENT_QUOTES|ENT_HTML5);$p='';foreach(preg_split('/\R+/',$text) as $line)if(trim($line)!=='')$p.='<w:p><w:r><w:t xml:space="preserve">'.htmlspecialchars(trim($line),ENT_XML1).'</w:t></w:r></w:p>';$z->addFromString('word/document.xml','<?xml version="1.0" encoding="UTF-8"?><w:document xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:body>'.$p.'<w:sectPr/></w:body></w:document>');$z->close();header('Content-Type: application/vnd.openxmlformats-officedocument.wordprocessingml.document');header('Content-Disposition: attachment; filename="lead-magnet.docx"');readfile($tmp);unlink($tmp);exit;}
if(preg_match('#^/published/lead-magnet/([a-z0-9]+)(?:\.(pdf|docx))?$#',$path,$m)){$s=db()->prepare("SELECT * FROM lead_magnets WHERE public_slug=? AND status='published'");$s->execute([$m[1]]);$r=$s->fetch();if(!$r){http_response_code(404);exit('Not found');}if(($m[2]??'')==='pdf')lm_pdf($r);if(($m[2]??'')==='docx')lm_docx($r);header('Content-Type:text/html;charset=UTF-8');echo lm_page($r);exit;}
if(!str_starts_with($path,'/lead-magnets'))return;require_permission('lead_magnets.view');
if($path==='/lead-magnets'){$rows=db()->query('SELECT * FROM lead_magnets ORDER BY updated_at DESC')->fetchAll();layout('Lead Magnet Generator',function()use($rows){?><div class="actions"><h1 style="margin:0">Lead Magnet Generator</h1><span class="spacer"></span><?php if(can('lead_magnets.edit')):?><a class="btn" href="/lead-magnets/new">Create lead magnet</a><?php endif?></div><div class="card"><table><thead><tr><th>Title</th><th>Type</th><th>Status</th><th>Updated</th></tr></thead><tbody><?php foreach($rows as $r):?><tr><td><a href="/lead-magnets/<?=$r['id']?>"><?=e($r['title'])?></a></td><td><?=e(option_label('lead_magnet_type',$r['magnet_type']))?></td><td><?=e($r['status'])?></td><td><?=e($r['updated_at'])?></td></tr><?php endforeach?></tbody></table></div><?php });exit;}
if($path==='/lead-magnets/new'){require_permission('lead_magnets.edit');if($method==='POST'){verify_csrf();try{$fields=['title','magnet_type','other_type','target_audience','desired_outcome','audience_problem','tone','call_to_action','brand_requirements','additional_instructions'];$v=[];foreach($fields as $f)$v[$f]=trim((string)post($f));if($v['title']===''||$v['target_audience']==='')throw new RuntimeException('Title and target audience are required.');$prompt="Create a {$v['magnet_type']} titled {$v['title']}. Audience: {$v['target_audience']}. Outcome: {$v['desired_outcome']}. Problem: {$v['audience_problem']}. Tone: {$v['tone']}. CTA: {$v['call_to_action']}. Brand: {$v['brand_requirements']}. Additional: {$v['additional_instructions']}. Approved knowledge:\n".lm_context();$html=lm_ai($prompt);db()->prepare('INSERT INTO lead_magnets(user_id,title,magnet_type,other_type,target_audience,desired_outcome,audience_problem,tone,call_to_action,brand_requirements,additional_instructions,content_html) VALUES(?,?,?,?,?,?,?,?,?,?,?,?)')->execute([user()['id'],$v['title'],$v['magnet_type'],$v['other_type']?:null,$v['target_audience'],$v['desired_outcome'],$v['audience_problem'],$v['tone'],$v['call_to_action'],$v['brand_requirements'],$v['additional_instructions'],$html]);$id=(int)db()->lastInsertId();audit('create','lead_magnet',$id);redirect('/lead-magnets/'.$id);}catch(Throwable $e){flash('error',$e->getMessage());}}layout('Create lead magnet',function(){?><h1>Create lead magnet</h1><form class="card" method="post"><input type="hidden" name="_csrf" value="<?=csrf()?>"><div class="form-grid"><label>Title<input name="title" required></label><label>Type<select name="magnet_type"><?php foreach(list_options('lead_magnet_type') as $o):?><option value="<?=e($o['code'])?>"><?=e($o['label'])?></option><?php endforeach?></select></label><label>Other type<input name="other_type"></label><label>Target audience<textarea name="target_audience" required></textarea></label><label>Desired outcome<textarea name="desired_outcome"></textarea></label><label>Primary problem<textarea name="audience_problem"></textarea></label><label>Tone<input name="tone"></label><label>Call to action<textarea name="call_to_action"></textarea></label><label>Brand requirements<textarea name="brand_requirements"></textarea></label><label class="full">Additional instructions<textarea name="additional_instructions"></textarea></label></div><button>Generate</button></form><?php });exit;}
if(preg_match('#^/lead-magnets/(\d+)(?:/(pdf|docx))?$#',$path,$m)){$r=lm_row((int)$m[1]);if(($m[2]??'')==='pdf')lm_pdf($r);if(($m[2]??'')==='docx')lm_docx($r);if($method==='POST'){require_permission('lead_magnets.edit');verify_csrf();try{$a=(string)post('action');if($a==='save')db()->prepare('UPDATE lead_magnets SET title=?,content_html=? WHERE id=?')->execute([trim((string)post('title')),lm_clean((string)post('content_html')),$r['id']]);elseif($a==='refine'){$req=trim((string)post('message'));$html=lm_ai("Return the complete revised HTML. Revision request: {$req}\nCurrent document:\n{$r['content_html']}\nKnowledge:\n".lm_context());db()->prepare('UPDATE lead_magnets SET content_html=? WHERE id=?')->execute([$html,$r['id']]);db()->prepare("INSERT INTO lead_magnet_messages(lead_magnet_id,user_id,role,message) VALUES(?,?,'user',?),(?,?,'assistant',?)")->execute([$r['id'],user()['id'],$req,$r['id'],user()['id'],$html]);}elseif($a==='publish'){db()->prepare("UPDATE lead_magnets SET status='published',public_slug=COALESCE(public_slug,?),published_at=NOW() WHERE id=?")->execute([bin2hex(random_bytes(8)),$r['id']]);}elseif($a==='archive')db()->prepare("UPDATE lead_magnets SET status='archived' WHERE id=?")->execute([$r['id']]);audit($a,'lead_magnet',(int)$r['id']);flash('success','Lead magnet updated.');}catch(Throwable $e){flash('error',$e->getMessage());}redirect('/lead-magnets/'.$r['id']);}$url=$r['public_slug']?rtrim((string)config('url'),'/').'/published/lead-magnet/'.$r['public_slug']:'';layout($r['title'],function()use($r,$url){?><div class="actions"><h1 style="margin:0"><?=e($r['title'])?></h1><span class="spacer"></span><a class="btn secondary" href="/lead-magnets/<?=$r['id']?>/pdf">PDF</a><a class="btn secondary" href="/lead-magnets/<?=$r['id']?>/docx">DOCX</a></div><?php if($url):?><div class="card"><strong>Public URL:</strong> <a href="<?=e($url)?>" target="_blank"><?=e($url)?></a></div><?php endif?><form class="card" method="post"><input type="hidden" name="_csrf" value="<?=csrf()?>"><label>Title<input name="title" value="<?=e($r['title'])?>"></label><label>Content HTML<textarea name="content_html" rows="24"><?=e($r['content_html'])?></textarea></label><div class="actions"><button name="action" value="save">Save</button><button class="secondary" name="action" value="publish">Publish</button><button class="danger" name="action" value="archive">Archive</button></div></form><form class="card" method="post"><input type="hidden" name="_csrf" value="<?=csrf()?>"><input type="hidden" name="action" value="refine"><h2>Refine with AI</h2><label>Request<textarea name="message" required></textarea></label><button>Refine</button></form><?php });exit;}
